package com.weekend.architect.unift.security;import com.weekend.architect.unift.auth.model.User;import lombok.Getter;import lombok.RequiredArgsConstructor;import org.springframework.security.core.GrantedAuthority;import org.springframework.security.core.authority.SimpleGrantedAuthority;import org.springframework.security.core.userdetails.UserDetails;import java.time.OffsetDateTime;import java.util.Collection;import java.util.List;@RequiredArgsConstructorpublic class UniFtUserDetails implements UserDetails {    @Getter    private final User user;    @Override    public Collection<? extends GrantedAuthority> getAuthorities() {        return List.of(new SimpleGrantedAuthority("ROLE_" + user.getRole()));    }    @Override    public String getPassword() {        return user.getPassword();    }    @Override    public String getUsername() {        return user.getUsername();    }    @Override    public boolean isAccountNonExpired() {        return true;    }    @Override    public boolean isAccountNonLocked() {        return user.getLockedUntil() == null || user.getLockedUntil().isBefore(OffsetDateTime.now());    }    @Override    public boolean isCredentialsNonExpired() {        return true;    }    @Override    public boolean isEnabled() {        return user.isActive() && user.getDeletedAt() == null;    }}